Question: How many consecutive days did A4F_69129's frequency of subcategory 'Legumes' meals in food_meal_labels decrease, while his/her nightly_temperature in skin_temp_sleep_nightly increased and his/her full_sleep_breathing_rate in respiratory_rate decreased, starting from 2022-05-18?
Output requirement: return 1 value(s); types (ordered): {integer}

GeneratedSQL:
WITH meal_data AS (
    SELECT DATE(ts) AS meal_date, COUNT(*) AS meal_count
    FROM food_meal_labels
    WHERE id = 'A4F_69129' AND subcategory = 'Legumes' AND DATE(ts) >= '2022-05-18'
    GROUP BY meal_date
),
temperature_data AS (
    SELECT DATE(start_sleep) AS sleep_date, AVG(nightly_temperature) AS avg_temperature
    FROM skin_temp_sleep_nightly
    WHERE id = 'A4F_69129' AND DATE(start_sleep) >= '2022-05-18'
    GROUP BY sleep_date
),
breathing_data AS (
    SELECT DATE(night_end) AS breathing_date, AVG(full_sleep_breathing_rate) AS avg_breathing_rate
    FROM respiratory_rate
    WHERE id = 'A4F_69129' AND DATE(night_end) >= '2022-05-18'
    GROUP BY breathing_date
),
combined_data AS (
    SELECT m.meal_date, m.meal_count, t.avg_temperature, b.avg_breathing_rate
    FROM meal_data m
    JOIN temperature_data t ON m.meal_date = t.sleep_date
    JOIN breathing_data b ON m.meal_date = b.breathing_date
)
SELECT COUNT(*) AS consecutive_days
FROM (
    SELECT *,
           @prev_meal_count := meal_count,
           @prev_temperature := avg_temperature,
           @prev_breathing_rate := avg_breathing_rate,
           @is_decreasing := IF(meal_count < @prev_meal_count AND avg_temperature > @prev_temperature AND avg_breathing_rate < @prev_breathing_rate, 1, 0) AS is_decreasing,
           @prev_meal_count := meal_count,
           @prev_temperature := avg_temperature,
           @prev_breathing_rate := avg_breathing_rate
    FROM combined_data, (SELECT @prev_meal_count := NULL, @prev_temperature := NULL, @prev_breathing_rate := NULL, @is_decreasing := 0) AS vars
    ORDER BY meal_date
) AS subquery
WHERE is_decreasing = 1;
